module mux4to1(  
    input wire [3:0] data,  
    input wire [1:0] sel,  
    output wire mux_out  
);  
    wire neg_mux_output = (sel == 2'b00);
    assign mux_out = neg_mux_output ? data[0] : (sel == 2'b01) ? data[1] :  
                     (sel == 2'b10) ? data[2] :  
                     data[3];  
endmodule
